def tbl(rows,widths,header=True,font='S'):
 data=[[P(v,'CW' if header and i==0 else ('CB' if j==0 else font)) for j,v in enumerate(r)] for i,r in enumerate(rows)]
 t=Table(data,colWidths=widths,repeatRows=1 if header else 0,hAlign='LEFT')
 cmd=[('VALIGN',(0,0),(-1,-1),'TOP'),('GRID',(0,0),(-1,-1),.35,LINE),('LEFTPADDING',(0,0),(-1,-1),4),('RIGHTPADDING',(0,0),(-1,-1),4),('TOPPADDING',(0,0),(-1,-1),4),('BOTTOMPADDING',(0,0),(-1,-1),4)]
 if header: cmd.append(('BACKGROUND',(0,0),(-1,0),GREEN))
 for i in range(1 if header else 0,len(rows)):
  if i%2==0: cmd.append(('BACKGROUND',(0,i),(-1,i),PAPER))
 t.setStyle(TableStyle(cmd)); return t
