def plan_day(p,wd,wk,load):
 # load: 0.75/0.9/1.0/0.6 по неделе микроцикла
 pull=max(4,round((8+p*1.2)*load)); dip=max(7,round((14+p*2)*load)); sets=5 if load>=.9 else 4
 warm='Разминка 10 мин: ходьба 3; круги суставов 2; лопаточные подтягивания 2×8 (45 с); лёгкие повторы 2×5 (60 с). '
 cool='Заминка 7 мин: спокойная ходьба 3; грудные/широчайшие/предплечья по 40 с ×2; дыхание 2 мин.'
 if p==1:
  return ('ПОСЛЕОПЕРАЦИОННЫЙ РЕЖИМ','Выполнить только письменное назначение хирурга. При разрешении: прогулка 10–30 мин в разговорном темпе + дыхание 5 мин. Запрещены натуживание, висы, гири, бег и тесты до отдельного допуска.','15–40 мин')
 if wd==0:
  body=f'1) Подтягивания {sets}×{pull}, темп 2–1–2, RIR 2–3, отдых 2:30. 2) Тяга гири 24 кг {sets}×10/сторона, 1 с фиксация, отдых 75 с между сторонами и 2 мин между подходами. 3) Подъём коленей в висе 4×12, 75 с. 4) Hollow hold 4×30–45 с, 60 с.'
  return ('ТЯГА + КОРПУС',warm+body+' '+cool,'65–75 мин')
 if wd==1:
  if p<2: run='Бег запрещён. Быстрая ходьба 40 мин; если колено шатается — 20–30 мин спокойно.'
  else:
   easy=min(50,25+p*4); run=f'Только после допуска: лёгкий бег {easy} мин по ровному мягкому покрытию, темп 4:55–5:35/км, разговорный RPE 3–4. Первые 2 недели: 8×(2 мин бег / 1 мин шаг). Без допуска — ходьба {easy+10} мин.'
  return ('АЭРОБНАЯ БАЗА',f'Разминка: ходьба 8 мин + мобилизация голеностопа/бедра 5 мин. {run} Заминка: шаг 7 мин. Оценить боль сразу и через 24 ч.','50–70 мин')
 if wd==2:
  body=f'1) Брусья {sets}×{dip}, темп 2–1–1, RIR 2–3, отдых 2:00. 2) Жим гири 16 кг 5×8/сторона, 75 с между сторонами, 2 мин между кругами. 3) Отжимания 3×15–25, RIR 3, 90 с. 4) Боковая планка 3×40 с/сторона, 45 с.'
  return ('ЖИМ + СТАБИЛИЗАЦИЯ',warm+body+' '+cool,'65–75 мин')
 if wd==3:
  return ('ВОССТАНОВЛЕНИЕ','Спокойная прогулка 30–45 мин. Затем 15 мин: голеностоп к стене 2×10/сторона; разгибание грудного отдела 2×8; растяжка сгибателей бедра 2×40 с; дыхание 4 с вдох / 6 с выдох — 5 мин. Никакой работы до отказа.','50–60 мин')
 if wd==4:
  mins=min(20,8+p*2); reps=3 if p<4 else 4
  body=f'1) Рывок 16 кг: EMOM {mins} мин, нечётная минута {reps}/левая, чётная {reps}/правая; остаток минуты — отдых. 3 мин отдыха. 2) 24 кг: {sets}×3–6/сторона только при чистой технике, 60 с между руками, 2:30 между подходами. 3) Перенос 24 кг 5×40 с/сторона, 60 с. Стоп при ударах гири по предплечью или потере фиксации.'
  return ('ГИРЯ — ТЕХНИКА И ПЛОТНОСТЬ','Разминка 12 мин: кисти/плечи/таз; мах 16 кг 3×10 с паузой 60 с. '+body+' Заминка 6 мин.','55–70 мин')
 if wd==5:
  ksu=max(3,round((4+p*1.5)*load))
  return ('ЭКЗАМЕНАЦИОННАЯ ТЕХНИКА + КСУ',f'1) Разминка 15 мин: шаг 5; суставы 4; беговые упражнения 4; 2 свободных ускорения по 40 м только после допуска. 2) КСУ {ksu} подходов × 2–5 чистых циклов, отдых 2:30, RIR 2. 3) Связка спецкросса: 2–4 круга — 200 м легко + 10 отжиманий + 5 прыжков по 1,8–2,0 м; отдых 3 мин между кругами. Это не дополнительная интервальная тренировка. 4) Заминка 8 мин.','65–100 мин')
 return ('ПОЛНЫЙ ОТДЫХ','Без тренировки. Можно 20–30 мин спокойной прогулки. Сон 8–9 ч; подготовить еду; записать утренний пульс, массу, сон, боль колена и усталость. Если два показателя в жёлтой зоне — следующую неделю снизить на 30%.','0–30 мин')

# Версия 4.1: весь бег учтён; пик 55–65 км только после устойчивой адаптации.
