run_km=[0,0,0,0,0,0,0,18,22,26,22,32,36,40,32,40,44,48,38,46,50,54,42,50,54,58,46,54,58,62,50,36,16]
run_contacts=[0,0,0,0,0,0,0,3,3,4,3,4,4,5,4,5,5,5,4,5,5,5,4,5,5,5,4,5,5,5,4,4,2]

def running_session(wk,wd):
 km=run_km[wk-1]; c=run_contacts[wk-1]
 if c==0: return None
 # Расклад: ПН легко, ЧТ качество, ПТ восстановление, ВС длительно/специфика.
 # Суббота остаётся днём КСУ, челноков и экзаменационной техники в пределах 2 часов.
 if c==2:
  days=[0,6]
 elif c==3:
  days=[0,3,6]
 elif c==4:
  days=[0,1,3,6]
 else:
  days=[0,1,3,4,6]
 if wd not in days: return None
 if c==2: shares={0:.42,6:.58}
 elif c==3: shares={0:.30,3:.32,6:.38}
 elif c==4: shares={0:.25,1:.18,3:.25,6:.32}
 else: shares={0:.22,1:.15,3:.22,4:.16,6:.25}
 dist=max(3,round(km*shares[wd]))
 if wk<=9:
  return f'Walk-run {dist} км: 10 мин ходьба; затем 8–12×(2 мин лёгкий бег / 1 мин шаг), остаток легко. RPE 2–3. Заминка 8 мин.'
 if wd==0:
  return f'Лёгкий бег {dist} км, 4:45–5:30/км, RPE 3, разговорный темп. После 6 зелёных недель: 6×20 с свободно, между ними 100 с шаг/трусца.'
 if wd==1:
  return f'Восстановительный бег {dist} км, 5:05–5:45/км, RPE 2–3. Выполнить утром или минимум за 4–6 часов до мяча/гири. Никаких ускорений.'
 if wd==4:
  return f'Лёгкий восстановительный бег {dist} км, 5:00–5:40/км, RPE 2–3. Никаких ускорений; гирю выполнять через 4–6 часов.'
 if wd==6:
  if wk in [18,22,26,30]: return f'Экзаменационная частичная репетиция: разминка 15 мин; спецкросс 2 км по актуальному коридору; затем легко до {dist} км. Не выполнять на максимум.'
  return f'Длительный лёгкий {dist} км, 4:55–5:35/км, RPE 3–4; не ускоряться последние 15 мин. Длительный ≤30% недели и ≤16 км. После бега: 10 мин шагом, питание в течение 60 мин и свободное восстановление до конца дня.'
 # четверг: одна качественная сессия, включая разминку/заминку
 if wk<16: q='3×6 мин по 3:48–3:55/км, отдых 2 мин трусца'
 elif wk<21: q='5×800 м по 2:48–2:52, отдых 2:30 трусца'
 elif wk<26: q='4×1 км по 3:28–3:35, отдых 2:30 трусца'
 elif wk<31: q='5×1 км по 3:20–3:27, отдых 2:30–3:00 трусца'
 else: q='3×600 м в актуальном темпе 3 км, отдых 3 мин; без закисления'
 return f'Качественный бег, всего {dist} км: 2 км легко + drills 5 мин + {q} + легко до объёма + 10 мин заминка.'

def exam_insert(wk,wd):
 if wk<8: return ''
 deload=(wk%4==3)
 if wd==0:
  n=3 if deload else 5
  return f' КСУ-техника: {n}×2–4 чистых цикла, отдых 2 мин, RIR 3. После 4 мин: гиря 24 кг техника {n}×3/рука, 60 с между руками, 2 мин между подходами.'
 if wd==1:
  ball=4 if wk<16 else (6 if wk<25 else 8)
  return f' Мяч 5 кг — технический контакт: разминка плеч/таза 8 мин; {ball} бросков вперёд + {ball} назад по 70–85%, отдых 2:30–3:00; видео 2 лучших попыток; стоп при падении дальности >7–10%. Затем подтягивания EMOM 10 мин по 4–7 и брусья EMOM 10 мин по 8–14, остаток минуты отдых, RIR 3.'
 if wd==2:
  return ' Силовая специфика +16 кг: после основных брусьев и 5 мин отдыха выполнить подтягивания +16 кг 4×4–8 и брусья +16 кг 4×6–12, RIR 2, отдых 3 мин. Затем КСУ 4×2–4 технических цикла, отдых 2 мин. На разгрузочной неделе 3×4, 3×6 и 3×2.'
 if wd==4:
  ball=3 if deload else (5 if wk<20 else 7)
  return f' Второй контакт гири 24 кг: интервалы 10×(30 с работа / 60 с отдых), менять руку каждый интервал, техника важнее темпа; тяжёлым считается только пятничный контакт. После 5 мин: мяч 5 кг — мощность {ball} бросков вперёд + {ball} назад по 85–95%, отдых 3–4 мин, стоп при падении дальности >7–10%.'
 if wd==5 and wk>=12:
  spec='Частичная репетиция спецкросса: 2 круга по 500 м с полным экзаменационным набором упражнений, RPE 7, отдых 6 мин.' if wk%2==0 else 'Короткая связка спецкросса: 4×(200 м + 10 отжиманий + 5 прыжков), отдых 3 мин.'
  full=' Полная репетиция блоков на 85–95% вместо обычной субботы.' if wk in [18,22,26,30] else ''
  return f' Челнок/скорость, только после допуска: чередовать акценты. Неделя A — 4×60 м, отдых 4 мин + 4×10 м 3 попытки, отдых 3 мин; неделя B — 3×100 м по 90–95%, отдых 5 мин + 10×10 м 2 попытки, отдых 5 мин. {spec}{full}'
 return ''

_old_plan_day=plan_day
def plan_day(p,wd,wk,load):
 title,text,duration=_old_plan_day(p,wd,wk,load)
 # Полный послеоперационный перерыв до конца августа.
 if 5<=wk<=7:
  return ('ПОСЛЕОПЕРАЦИОННЫЙ НОЛЬ','Тренировки отсутствуют. Только лекарства, бытовая активность, прогулки и реабилитация, прямо разрешённые хирургом. Августовский отдых не доказывает восстановление колена.','по назначению врача')
 run=running_session(wk,wd)
 if run and wd==6:
  title='ДЛИТЕЛЬНЫЙ БЕГ + ВОССТАНОВЛЕНИЕ'
  text='<b>БЕГОВАЯ СЕССИЯ (только после двух допусков):</b> '+run+' Без допуска: 35–50 мин ходьбы без боли. После завершения — никаких силовых, прыжков, челноков или дополнительных пробежек.'
  duration='70–130 мин с разминкой и заминкой'
 elif run:
  text='<b>БЕГОВАЯ СЕССИЯ (только после двух допусков):</b> '+run+' Без допуска: 35–50 мин ходьбы без боли. Отдельную силовую выполнять через 4–6 часов. '+text
 text += exam_insert(wk,wd)
 if wk==8:
  text += ' Диагностическая неделя: не совмещать максимумы. За неделю отдельно зафиксировать +16 кг, технику 24 кг, сумму двух бросков и сокращённый спецкросс.'
 if wk in [12,16,20,24,28]:
  text += ' Контрольные ворота недели: проверить только 2 приоритетных показателя; отставание переводит следующие 2 недели в корректирующий блок, заменяя дополнительный объём.'
 if wk==31:
  text += ' Последняя полная репетиция экзаменационных блоков на 90–95%; после неё никаких полных репетиций.'
 if wk>=32:
  text += ' ПОДВОДКА: объём снижен; сохранить короткую скорость и технику. Никаких отказных добивок.'
 return (title,text,duration)

